CREATE SCHEMA invest_berkshire;
USE invest_berkshire;
SELECT DATABASE();

CREATE TABlE customer_details(
customer_id       INT,
PRIMARY KEY(customer_id),
full_name         VARCHAR(255),
first_name        VARCHAR(100),
last_name         VARCHAR(100),
email             VARCHAR(200),
customer_location VARCHAR(100)
); #closing the create table for customer_details


#end of customer_details

CREATE TABLE account_dim(
account_id INT,
PRIMARY KEY(account_id),
client_id INT,
main_account VARCHAR(100),
acct_open_date DATE,
acct_open_status INT,
FOREIGN KEY(client_id) REFERENCES customer_details(customer_id)
); #closing the create table for account_id


#end of account_dim

CREATE TABLE holdings_current(
account_id INT,
ticker VARCHAR(8),
acct_ticker VARCHAR(100),
PRIMARY KEY(acct_ticker),
date DATE,
variable VARCHAR(200),
value DOUBLE,
price_type VARCHAR(200),
quantity DOUBLE,
FOREIGN KEY(account_id) REFERENCES account_dim(account_id),
FOREIGN KEY(ticker)     REFERENCES security_masterlist(ticker)
); #closing the create table for holdings_current


#end of current_holdings

CREATE TABLE security_masterlist(
ticker VARCHAR(8),
PRIMARY KEY(ticker),
id BIGINT,
security_name TEXT,
sp500_weight DOUBLE,
sec_type VARCHAR(100),
major_asset_class VARCHAR(100),
minor_asset_class VARCHAR(100)
); #closing the create table for secutity_masterlist

'AAPL', 1, 'Apple Inc.', 7.02, 'Common Stock', 'Equity', 'Information Technology'),
('BAC', 2, 'Bank of America Corporation', 0.89, 'Common Stock', 'Equity', 'Financials'),
('KO', 3, 'The Coca-Cola Company', 0.71, 'Common Stock', 'Equity', 'Consumer Staples'),
('AXP', 4, 'American Express Company', 0.55, 'Common Stock', 'Equity', 'Financials'),
('CVX', 5, 'Chevron Corporation', 1.18, 'Common Stock', 'Equity', 'Energy');


#end of security_masterlist

CREATE TABLE pricing_client(
FIELD1 INT,
PRIMARY KEY(FIELD1),
account_id INT,
customer_id INT,
ticker VARCHAR(8),
date DATE,
variable VARCHAR(200),
value DOUBLE,
price_type VARCHAR(200),
FOREIGN KEY(account_id)  REFERENCES account_dim(account_id),
FOREIGN KEY(customer_id) REFERENCES customer_details(customer_id),
FOREIGN KEY(ticker) REFERENCES security_masterlist(ticker)
); #closing the create table for pricing_client

