#FULL ANALYSIS & RECOMMENDATION BEGINS HERE FOR CLIENT PORTFOLIO

#Verification exercise

SELECT ticker, COUNT(*)        AS total_rows, MIN(date)       AS start_date, MAX(date)       AS end_date
FROM pricing_client
WHERE price_type = 'Adjusted'
GROUP BY ticker
ORDER BY ticker;

#Sanity check below on security_masterlsit

SELECT distinct p.ticker, p.price_type, s.security_name, s.major_asset_class, s.minor_asset_class
FROM pricing_client P
JOIN security_masterlist s ON p.ticker = s.ticker
ORDER BY p.ticker, p.price_type;

#Current Portfolio: Total Return Per Stock - Period: 2021-01-04 to 2023-01-18 (3 Years) Uses Adjusted close price (accounts for dividends/splits)

SELECT 
p.ticker, 
s.security_name, 
s.minor_asset_class AS sector,
ROUND(MIN(CASE WHEN p.date = start_dates.min_date THEN p.value END), 2) AS start_price,
ROUND(MIN(CASE WHEN p.date = end_dates.max_date THEN p.value END), 2) AS end_price,
ROUND((MIN(CASE WHEN p.date = end_dates.max_date THEN p.value END) - MIN(CASE WHEN p.date = start_dates.min_date THEN p.value END)) / MIN(CASE WHEN p.date = start_dates.min_date THEN p.value END) * 100, 2) AS total_return_pct
FROM pricing_client p
JOIN security_masterlist s ON p.ticker = s.ticker
JOIN (
SELECT ticker, MIN(date) AS min_date FROM pricing_client 
WHERE price_type = 'Adjusted' AND date BETWEEN '2021-01-01' AND '2023-12-31' 
GROUP BY ticker) AS start_dates ON p.ticker = start_dates.ticker
JOIN (
SELECT ticker, MAX(date) AS max_date
FROM pricing_client
WHERE price_type = 'Adjusted'
AND date BETWEEN '2021-01-01' AND '2023-12-31'
GROUP BY ticker
) AS end_dates ON p.ticker = end_dates.ticker
WHERE p.price_type = 'Adjusted' AND p.date BETWEEN '2021-01-01' AND '2023-12-31'
GROUP BY p.ticker, s.security_name, s.minor_asset_class
ORDER BY total_return_pct DESC;

