### DAILY VIEW RETURN BELOW ###

CREATE OR REPLACE VIEW daily_returns AS
SELECT ticker, date, value AS close_price,
LAG(value) OVER (PARTITION BY ticker ORDER BY date) AS prev_close,
ROUND((value - LAG(value) OVER (PARTITION BY ticker ORDER BY date)) / LAG(value) OVER (PARTITION BY ticker ORDER BY date), 6) AS daily_return
FROM pricing_client
WHERE price_type = 'Adjusted'
AND date BETWEEN '2021-01-01' AND '2023-12-31';

### Verfication Method ###

SELECT 
ticker,
COUNT(*) AS trading_days
FROM daily_returns
GROUP BY ticker
ORDER BY ticker;

SELECT ticker,
COUNT(*) AS trading_days,
MIN(date) AS start_date, 
MAX(date) AS end_date,
ROUND(MIN(daily_return) * 100, 2) AS worst_day_pct,
ROUND(MAX(daily_return) * 100, 2) AS best_day_pct
FROM daily_returns
GROUP BY ticker
ORDER BY ticker;

#############################################################################

### KEY FINDINGS ###

-- KO = Lowest best day (+3.87%) = most defensive/stable
-- AXP = Highest volatility range (-8.62% to +8.92%)
-- All tickers = 514 trading days perfectly aligned

#############################################################################

#end of create view


### RISK & RETURN SUMMARY PER STOCK ###

SELECT 
d.ticker, 
s.security_name, 
s.minor_asset_class AS sector,
ROUND(AVG(d.daily_return) * 252 * 100, 2) AS annualized_return_pct,
ROUND(STDDEV(d.daily_return) * SQRT(252) * 100, 2) AS annualized_volatility_pct,
ROUND((AVG(d.daily_return) * 252 - 0.04) / NULLIF(STDDEV(d.daily_return) * SQRT(252), 0), 3) AS sharpe_ratio
FROM daily_returns d
JOIN security_masterlist s ON d.ticker = s.ticker
WHERE d.daily_return IS NOT NULL
GROUP BY d.ticker, s.security_name, s.minor_asset_class
ORDER BY sharpe_ratio DESC; 

###################################################################################################################################

### KEY FINDINGS & OBSERVATION ###

-- CVX = Sharpe 1.41 = EXCELLENT risk-adjusted return 44.71% return | 28.87% volatility (UNDERWEIGHTED at 30%)
-- AXP = Sharpe 0.451 = GOOD 18.36% return | 31.83% volatility (UNDERWEIGHTED at 7%)
-- KO = Sharpe 0.381 = MODERATE but lowest volatility (17.46%). Best defensive stock (UNDERWEIGHTED at 8%)
-- BAC = Sharpe 0.274 = BELOW AVERAGE 11.99% return | 29.13% volatility
-- AAPL = Sharpe 0.113 = POOR risk-adjusted return 7.47% return | 30.78% volatility (OVER-CONCENTRATED at 44% CORE PROBLEM)

## AAPL = 44% weight - Sharpe 0.113 (WORST)
## CVX = 30% weight - Sharpe 1.41  (BEST)

## The portfolio has maximum weight in its worst risk-adjusted performer and minimum weight in its best performer. ##

###################################################################################################################################

#end of risk & return summary


### CURRENT PORTFOLIO PERFORMANCE ###

WITH stock_metrics AS (
SELECT
ticker,
AVG(daily_return) * 252 AS ann_return,
STDDEV(daily_return) * SQRT(252) AS ann_vol
FROM daily_returns
WHERE daily_return IS NOT NULL
GROUP BY ticker
),
portfolio_weights AS (
SELECT 'AAPL' AS ticker, 0.44 AS weight_val UNION ALL
SELECT 'BAC', 0.11 UNION ALL
SELECT 'KO',  0.08 UNION ALL
SELECT 'AXP', 0.07 UNION ALL
SELECT 'CVX', 0.30
)
SELECT
'CURRENT (BERKSHIRE)' AS portfolio_type,
ROUND(SUM(w.weight_val * m.ann_return) * 100, 2) AS portfolio_return_pct,
ROUND(SUM(w.weight_val * m.ann_vol) * 100, 2) AS portfolio_risk_pct,
ROUND(
(SUM(w.weight_val * m.ann_return) - 0.04) / NULLIF(SUM(w.weight_val * m.ann_vol), 0), 3) AS portfolio_sharpe
FROM portfolio_weights w
JOIN stock_metrics m USING (ticker);

