### CONCENTRATION RISK - PROBLEM IDENTIFICATION ###

SELECT
d.ticker,
s.security_name,
s.minor_asset_class AS sector,
CASE d.ticker
WHEN 'AAPL' THEN 44
WHEN 'BAC'  THEN 11
WHEN 'KO'   THEN 8
WHEN 'AXP'  THEN 7
ELSE 30
END AS current_weight_pct,
ROUND(AVG(d.daily_return) * 252 * 100, 2) AS annual_return_pct,
ROUND(STDDEV(d.daily_return) * SQRT(252) * 100, 2) AS annual_risk_pct,
ROUND((AVG(d.daily_return) * 252 - 0.04) / NULLIF(STDDEV(d.daily_return) * SQRT(252), 0), 3) AS sharpe_ratio,
CASE
WHEN d.ticker = 'AAPL' THEN 'OVER-CONCENTRATED'
WHEN STDDEV(d.daily_return) * SQRT(252) * 100 > 35 THEN 'HIGH RISK'
WHEN (AVG(d.daily_return) * 252 - 0.04) / NULLIF(STDDEV(d.daily_return) * SQRT(252), 0) > 0.8 THEN 'STRONG'
ELSE 'MODERATE'
END  AS assessment
FROM daily_returns d
JOIN security_masterlist s ON d.ticker = s.ticker
WHERE d.daily_return IS NOT NULL
GROUP BY d.ticker, s.security_name, s.minor_asset_class
ORDER BY current_weight_pct DESC;


###########################################################################################################

#### KEY FINDINGS & OBSERVATION ###

-- AAPL = 44% weight | Sharpe 0.113 | OVER-CONCENTRATED (Highest weight in WORST performing stock).
-- CVX = 30% weight | Sharpe 1.41  | STRONG (Best performer but UNDERWEIGHTED).
-- BAC = 11% weight | Sharpe 0.274 | MODERATE.
-- KO = 8% weight | Sharpe 0.381 | MODERATE (Lowest volatility (17.46%) - stability anchor).
-- AXP = 7% weight | Sharpe 0.451 | MODERATE (Hidden gem - underweighted relative to performance).
    
### CORE PROBLEM ###

-- Maximum weight in worst performer (AAPL)
-- Minimum weight in best performer (AXP)
-- Solution: Rebalance towards CVX, AXP and KO

###########################################################################################################

#end of concentration risk & problem identification


### OPTIMIZED PORTFOLIO - REBALANCED WEIGHTS ###

SELECT
'OPTIMIZED' AS portfolio_type,
ROUND((
(0.20 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'AAPL' AND daily_return IS NOT NULL)) +
(0.10 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'BAC'  AND daily_return IS NOT NULL)) +
(0.15 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'KO'   AND daily_return IS NOT NULL)) +
(0.20 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'AXP'  AND daily_return IS NOT NULL)) +
(0.35 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'CVX'  AND daily_return IS NOT NULL))) * 100, 2) AS portfolio_return_pct,
ROUND((
(0.20 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'AAPL' AND daily_return IS NOT NULL)) +
(0.10 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'BAC'  AND daily_return IS NOT NULL)) +
(0.15 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'KO'   AND daily_return IS NOT NULL)) +
(0.20 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'AXP'  AND daily_return IS NOT NULL)) +
(0.35 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'CVX'  AND daily_return IS NOT NULL))) * 100, 2) AS portfolio_risk_pct,
ROUND((
(0.20 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'AAPL' AND daily_return IS NOT NULL)) +
(0.10 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'BAC'  AND daily_return IS NOT NULL)) +
(0.15 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'KO'   AND daily_return IS NOT NULL)) +
(0.20 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'AXP'  AND daily_return IS NOT NULL)) +
(0.35 * (SELECT AVG(daily_return) * 252 FROM daily_returns WHERE ticker = 'CVX'  AND daily_return IS NOT NULL)) - 0.04
) / (
(0.20 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'AAPL' AND daily_return IS NOT NULL)) +
(0.10 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'BAC'  AND daily_return IS NOT NULL)) +
(0.15 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'KO'   AND daily_return IS NOT NULL)) +
(0.20 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'AXP'  AND daily_return IS NOT NULL)) +
(0.35 * (SELECT STDDEV(daily_return) * SQRT(252) FROM daily_returns WHERE ticker = 'CVX'  AND daily_return IS NOT NULL))), 3) AS portfolio_sharpe;


#################################################################

### KEY FINDINGS & OBSERVATION ###

## OPTIMIZED WEIGHTS ###

-- AAPL = 20% (reduced from 44%)
-- BAC = 10% (reduced from 11%)
-- KO = 15% (increased from 8%)
-- AXP = 20% (increased from 7%)
-- CVX = 35% (increased from 30%)

