### FULLY JOINED TABLES ###

SELECT
c.full_name AS client_name,
c.customer_location,
a.main_account,
a.acct_open_date,
h.ticker,
s.security_name,
s.minor_asset_class AS sector,
h.quantity,
h.value AS last_price,
ROUND(h.quantity * h.value / 1000000000, 2) AS holding_value_billions,
CASE h.ticker
WHEN 'AAPL' THEN 44
WHEN 'BAC'  THEN 11
WHEN 'KO'   THEN 8
WHEN 'AXP'  THEN 7
ELSE 30
END AS current_weight_pct,
CASE h.ticker
WHEN 'AAPL' THEN 20
WHEN 'BAC'  THEN 10
WHEN 'KO'   THEN 15
WHEN 'AXP'  THEN 20
ELSE 35
END AS optimized_weight_pct
FROM customer_details c
JOIN account_dim a ON c.customer_id = a.client_id
JOIN holdings_current h ON a.account_id = h.account_id
JOIN security_masterlist s ON h.ticker = s.ticker
ORDER BY current_weight_pct DESC;

